{
  "intent": "check",
  "intent_description": "Investigate and restore the OSPF adjacency that is down on device R2 so the OSPF neighbor becomes UP and routes are exchanged.",
  "target": "R2",
  "needs_fix": null,
  "plan": {
    "problem": "OSPF adjacency on R2 reported as down",
    "fix_summary": "diagnosis missing — no remediation planned until diagnosis is provided",
    "plan_steps": []
  }
}

{
  "root_causes": [
    {
      "type": "protocol/connectivity",
      "cause": "One-way OSPF Hello reception on the R1<->R2 Serial0/1/0 link: R1 sees R2's Hellos (neighbor in INIT) but R2 does not see R1 and reports no neighbor on the interface, preventing adjacency formation.",
      "evidence": [
        "router1 (Serial0/1/0): neighbor_id=2.2.2.2 neighbor_address=10.0.0.2 neighbor_state=ospf-nbr-init (get_ospf output for router1)",
        "router2 (Serial0/1/0): interface_state=Point-to-Point, neighbors=[] (get_ospf output for router2)"
      ],
      "confidence": 0.9
    }
  ],
  "missing_info": [
    "R1 and R2 interface IP/config on Serial0/1/0 (show running-config interface / show ip interface brief) to confirm addressing and subnet match",
    "Interface receive counters and error statistics on R2 Serial0/1/0 (show interfaces Serial0/1/0) to check for physical/CRC/input drops",
    "Any inbound ACLs or packet filters on R2 that could block OSPF (show access-lists / show running-config) and OSPF debug output on R2 (debug ip ospf hello) to confirm whether R1 Hellos arrive"
  ]
}

{
  "intent": "check_and_fix",
  "intent_description": "One-way OSPF Hello on the R1<->R2 Serial0/1/0 link: R1 sees R2 (INIT) but R2 reports no neighbor. Restore OSPF adjacency so the neighbor becomes UP and routes are exchanged.",
  "target": "R2",
  "needs_fix": true,
  "plan": {
    "problem": "One-way OSPF Hello reception on R2 Serial0/1/0 causing adjacency to remain down and preventing route exchange between R1 and R2.",
    "fix_summary": "On router2, configure Serial0/1/0 with the expected IP (10.0.0.2/30), ensure the interface is administratively up, and enable OSPF on the interface (OSPF process 1, area 0) so Hellos are transmitted/received and the adjacency can form.",
    "plan_steps": [
      {
        "id": 1,
        "device": "router2",
        "action": "configure_interface",
        "target": "Serial0/1/0",
        "parameters": [
          "ip address 10.0.0.2 255.255.255.252"
        ]
      },
      {
        "id": 2,
        "device": "router2",
        "action": "configure_interface",
        "target": "Serial0/1/0",
        "parameters": [
          "no shutdown"
        ]
      },
      {
        "id": 3,
        "device": "router2",
        "action": "configure_interface",
        "target": "Serial0/1/0",
        "parameters": [
          "ip ospf 1 area 0"
        ]
      }
    ]
  }
}

